SELECT a.*
FROM ai_chat_record a


        AND a.conversation_id = #{conversationId}


        AND a.user_id = #{userId}


        AND a.agent_type = #{agentType}


ORDER BY a.id DESC

    LIMIT #{current},#{size}

SELECT COUNT(*)
FROM ai_chat_record a


        AND a.conversation_id = #{conversationId}


        AND a.user_id = #{userId}


        AND a.agent_type = #{agentType}

SELECT * FROM ai_chat_record
WHERE conversation_id = #{conversationId}
ORDER BY id ASC

SELECT IFNULL(AVG(cnt), 0) FROM (
    SELECT COUNT(*) as cnt FROM ai_chat_record GROUP BY user_id
) t
